'@

# Convert SVG to base64
$svgBytes = [System.Text.Encoding]::UTF8.GetBytes($quidSvg)
$b64 = [System.Convert]::ToBase64String($svgBytes)
$newSrc = "data:image/svg+xml;base64,$b64"

# Find and replace the current quid img src
$imgStart = $c.IndexOf('class="s7-quid-img" src="')
if ($imgStart -lt 0) {
    Write-Host "ERROR: s7-quid-img not found"
    exit
}

$srcStart = $imgStart + 'class="s7-quid-img" src="'.Length
$srcEnd = $c.IndexOf('"', $srcStart)
$oldSrc = $c.Substring($srcStart, $srcEnd - $srcStart)
Write-Host "Old src length: $($oldSrc.Length)"

$c = $c.Substring(0, $srcStart) + $newSrc + $c.Substring($srcEnd)
Write-Host "New src length: $($newSrc.Length)"

# Also update the img style - ensure filter is removed (logo is already white)
$c = $c.Replace('class="s7-quid-img" src="' + $newSrc + '" style="height:44px;width:auto;object-fit:contain;filter:brightness(1.15)"',
                'class="s7-quid-img" src="' + $newSrc + '" style="height:52px;width:auto;object-fit:contain"')

# Also update the style without filter if it doesn't have filter
$c = $c.Replace('class="s7-quid-img" src="' + $newSrc + '" style="height:44px;width:auto;object-fit:contain"',
                'class="s7-quid-img" src="' + $newSrc + '" style="height:52px;width:auto;object-fit:contain"')

Write-Host "Quid logo replaced"

# Save
[System.IO.File]::WriteAllText($f, $c, [System.Text.Encoding]::UTF8)
Write-Host "DONE! Saved $($c.Length) chars"
